mapper.insert:
INSERT INTO course_schedule (
    course_id, start_week, end_week, week_type, weekday, start_section, end_section, start_time, end_time, classroom
) VALUES (
    #{courseId}, #{startWeek}, #{endWeek}, #{weekType}, #{weekday}, #{startSection}, #{endSection}, #{startTime}, #{endTime}, #{classroom}
)

mapper.select:
SELECT schedule_id, course_id, start_week, end_week, week_type, weekday, start_section, end_section, start_time, end_time, classroom, create_time, update_time
FROM course_schedule
WHERE classroom = #{classroom}
  AND start_week <= #{endWeek}
  AND #{startWeek} <= end_week
  AND weekday = #{weekday}
  AND start_time < #{endTime}
  AND #{startTime} < end_time
ORDER BY course_id ASC, start_time ASC
